#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    ret = texture( sampler_main, vUv ).xyz;

ret.x=1-ret.x;
    // ERROR DIFFUSION DITHER - looks great
    vec2 dither_uv = vUvOriginal*uTexSize.xy*texsize_noise_lq.zw + rand_frame.xy;
    ret += (texture(sampler_noise_lq, dither_uv).xyz-0.5)/256.0*1;
vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((vUv.xyy*q27
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*q29
                     );
if(ret.x> q21*q13         && ret.x<= q24*q11        )ret.y -= (noise9).x*.5;
ret.y=1-ret.y;

if(ret.y> q22*q11         && ret.y<= q25*q12        )ret.z -= (noise9).y*.5;
if(ret.z> q23*q12         && ret.z<= q26*q13        )ret.x -= (noise9).z*.5;
    // mix in img...
    vec3 pic = texture(sampler_pic, vUvOriginal).xyz;
    float lum = lum(pic);
    float use_it = abs(lum - fract((audioLow+audioMid+audioHigh)*0.2));
    use_it = clamp01(1 - use_it*33);
ret.z=1-ret.z;

    ret = mix(ret, pic, use_it.xxx);

    // darken over uTime
    //ret -= 0.004;
    //ret *= 0.99;
    ret *= 0.97 + 0.03*clamp01( length(vUv - vUvOriginal)*200 );  // center only

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv2;
//vUv = (vUv-0.5) * uAspect.xy + .5;
dz = 0;

vec2 hor = vec2(uTexSize.z,0);
vec2 ver = vec2(0,uTexSize.w);

float dist = 1;
float inten = 1;
ret1 = 0;
float anz = 1;
float n = 0;
uv4 = (vUv);
    dz.x = lum(GetPixel(uv4+hor)- GetPixel (uv4-hor));
    dz.y = lum(GetPixel(uv4+ver)- GetPixel (uv4-ver));


mus = .5*GetPixel(uv4-0*dz)-0*dz.x;

uv2 = vUv-.5;
while (n <= anz) {
    dist = 1-fract(1.0/anz*n-.1); //evtl sqrt !;

    inten =  sqrt(dist)*(1-dist*dist)*4;

    uv3 = q27*2*uv2*dist + vec2 (uTime/8,0);
    uv3 = fract(uv3);
    uv3 *= uAspect.yx;
    uv3 = .1 * cos(22*uv3) + 18 *dz ;
    neu = clamp01(.02/length(uv3));
    neu = dist*neu + (1-dist)*lum(neu)* .5*(1+roam_cos);
    ret1 = max(ret1,neu*inten);
vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((vec3(uv3.y*11/n,uv3.x*13/n,uv3.y/n)*q28
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*q31
                     );
if(ret1.x> q26*q13         && ret1.x<= q23*q11        )ret1.z -= (noise9).x*.5;
if(ret1.y> q25*q11         && ret1.y<= q22*q12        )ret1.x -= (noise9).y*.5;
if(ret1.z> q24*q12         && ret1.z<= q21*q13        )ret1.y -= (noise9).z*.5;
n++;
}

ret = ret1  +  clamp01(8*mus*(.2+ret1)) ;
ret=1-ret;

  fragColor = ret;
}
